// Collect all topic rows
const topics = $input.all().map(i => i.json);

if (!topics || topics.length === 0) {
  throw new Error('Topic queue is empty. Please add topics to your Google Sheets topic registry.');
}

// Filter enabled topics only
const enabled = topics.filter(t => String(t.enabled).toLowerCase() === 'true');
if (enabled.length === 0) {
  throw new Error('No enabled topics found. Set enabled=true for at least one topic.');
}

// 24-hour dedup: skip recently used topics
const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000);
const fresh = enabled.filter(t => !t.lastUsed || new Date(t.lastUsed) < yesterday);

// Sort by priority desc, then by lastUsed asc (least recently used first)
const pool = (fresh.length > 0 ? fresh : enabled).sort((a, b) => {
  const pd = (parseInt(b.priority) || 5) - (parseInt(a.priority) || 5);
  if (pd !== 0) return pd;
  const au = a.lastUsed ? new Date(a.lastUsed).getTime() : 0;
  const bu = b.lastUsed ? new Date(b.lastUsed).getTime() : 0;
  return au - bu;
});

const selected = pool[0];

const pollSession = {
  pollId: `POLL-${Date.now()}-${Math.random().toString(36).substr(2,7).toUpperCase()}`,
  topic: (selected.topic || 'General Community').trim(),
  category: (selected.category || 'General').trim(),
  priority: parseInt(selected.priority) || 5,
  language: selected.language || 'en',
  tone: selected.tone || 'professional',
  targetAudience: selected.targetAudience || 'community members',
  usageCount: parseInt(selected.usageCount || 0) + 1,
  totalTopics: enabled.length,
  freshTopics: fresh.length,
  scheduledAt: new Date().toISOString()
};

return [{ json: { pollSession } }];

// Parse GPT-4 output
const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';
if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || aiResponse.content[0]?.message?.content || '';
}
const clean = aiText.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();

let poll;
try { poll = JSON.parse(clean); }
catch(e) { throw new Error(`GPT-4 JSON parse failed: ${e.message}. Raw: ${clean.substring(0,200)}`); }

// Validation errors array
const errors = [];

// Question checks
if (!poll.question || !poll.question.trim()) errors.push('Question is empty');
else if (poll.question.length > 255) errors.push(`Question ${poll.question.length} chars — max 255`);

// Options checks
if (!Array.isArray(poll.options)) errors.push('Options must be an array');
else if (poll.options.length < 2) errors.push('Need at least 2 options');
else if (poll.options.length > 10) errors.push(`Too many options: ${poll.options.length} — max 10`);
else poll.options.forEach((o,i) => {
  if (!o || !o.trim()) errors.push(`Option ${i+1} is empty`);
  else if (o.length > 100) errors.push(`Option ${i+1}: ${o.length} chars — max 100`);
});

// Content safety
const blocked = ['hate','violence','explicit','illegal','discrimination'];
const allText = ((poll.question||'') + ' ' + (poll.options||[]).join(' ')).toLowerCase();
const hits = blocked.filter(w => allText.includes(w));
if (hits.length) errors.push(`Blocked keywords: ${hits.join(', ')}`);
if (poll.contentRating && poll.contentRating !== 'safe') errors.push(`Content flagged: ${poll.contentRating}`);

if (errors.length > 0) throw new Error(`Poll validation failed: ${errors.join(' | ')}`);

// Load groups from upstream
const pollSession = $('Select Highest Priority Topic').first().json.pollSession;
const groupRegistry = $('Load Telegram Group Registry').all().map(i => i.json);
const enabledGroups = groupRegistry.filter(g => String(g.enabled).toLowerCase() === 'true');

if (enabledGroups.length === 0) {
  throw new Error('No enabled groups in registry. Add groups to the Google Sheets group registry.');
}

// Safe-trim options
const safeOptions = poll.options.map(o => o.substring(0,100).trim());

return {
  json: {
    pollSession,
    pollContent: {
      question: poll.question.trim(),
      options: safeOptions,
      isAnonymous: poll.isAnonymous !== false,
      allowsMultipleAnswers: poll.allowsMultipleAnswers === true,
      openPeriod: Math.min(parseInt(poll.openPeriod) || 86400, 604800),
      hashtags: poll.hashtags || [],
      engagementScore: poll.engagementScore || 0,
      explanation: poll.explanation || ''
    },
    targetGroups: enabledGroups,
    groupCount: enabledGroups.length,
    validatedAt: new Date().toISOString()
  }
};

