const pollResp = $('Send Poll to Telegram Group').item.json;
const msgResp = $('Send Context Message with Hashtags').item.json;
const validated = $('Validate Poll Quality and Safety').first().json;

const idx = $runIndex || 0;
const grp = validated.targetGroups[idx] || validated.targetGroups[0];

const pollOk = pollResp?.ok === true || pollResp?.result?.message_id != null;
const pollErr = !pollOk ? (pollResp?.description || pollResp?.error || 'Unknown Telegram error') : null;
const msgOk = msgResp?.ok === true || msgResp?.result?.message_id != null;

return {
  json: {
    pollSession: validated.pollSession,
    pollContent: validated.pollContent,
    groupResult: {
      groupId: grp?.groupId || 'UNKNOWN',
      groupName: grp?.groupName || 'Unknown Group',
      groupType: grp?.groupType || 'group',
      pollSent: pollOk,
      contextMsgSent: msgOk,
      pollMessageId: pollResp?.result?.message_id || null,
      errorMessage: pollErr,
      deployedAt: new Date().toISOString()
    }
  }
};

const all = $input.all().map(i => i.json);
if (!all.length) throw new Error('No deploy results to summarise.');

const first = all[0];
const pollSession = first.pollSession;
const pollContent = first.pollContent;
const groupResults = all.map(r => r.groupResult);

const ok = groupResults.filter(g => g.pollSent);
const fail = groupResults.filter(g => !g.pollSent);
const successRate = groupResults.length > 0 ? Math.round((ok.length / groupResults.length) * 100) : 0;

// Telegram admin message (MarkdownV2-safe)
const adminLines = [
  `📊 *Poll Deployed*`,
  ``,
  `🆔 \`${pollSession.pollId}\``,
  `📌 *${pollSession.topic}*`,
  `🏷️ Category: ${pollSession.category}`,
  `❓ _${pollContent.question}_`,
  ``,
  `📤 Groups targeted: *${groupResults.length}*`,
  `✅ Successful: *${ok.length}*`,
  `❌ Failed: *${fail.length}*`,
  `📈 Success rate: *${successRate}%*`,
  `🎯 Engagement score: *${pollContent.engagementScore}/100*`,
  ``
];
if (fail.length > 0) {
  adminLines.push(`⚠️ *Failed groups:*`);
  fail.forEach(g => adminLines.push(`• ${g.groupName}: ${g.errorMessage || 'error'}`) );
}
adminLines.push(`\n⏱️ ${new Date().toISOString()}`);

return [{
  json: {
    pollSession,
    pollContent,
    groupResults,
    deploymentSummary: {
      totalGroups: groupResults.length,
      successfulGroups: ok.length,
      failedGroups: fail.length,
      successRate,
      failedGroupDetails: fail.map(g => ({ groupId: g.groupId, groupName: g.groupName, error: g.errorMessage })),
      completedAt: new Date().toISOString()
    },
    adminSummaryText: adminLines.join('\n')
  }
}];

const d = $input.item.json;
return {
  json: {
    success: true,
    pollId: d.pollSession.pollId,
    topic: d.pollSession.topic,
    category: d.pollSession.category,
    question: d.pollContent.question,
    options: d.pollContent.options,
    engagementScore: d.pollContent.engagementScore,
    deployment: d.deploymentSummary,
    scheduledAt: d.pollSession.scheduledAt,
    completedAt: d.deploymentSummary.completedAt,
    credit: {
      poweredBy: 'GPT-4o via n8n OpenAI integration',
      moreAutomation: 'https://www.oneclickitsolution.com/contact-us/'
    }
  }
};
